svg.script:
(function() {

  var urls = [
    "https://raw.githubusercontent.com/Darkdragonzxs/zd-pages/main/zodiac.html",
    "https://cdn.jsdelivr.net/gh/Darkdragonzxs/zd-pages@main/zodiac.html",
    "https://raw.githack.com/Darkdragonzxs/zd-pages/main/zodiac.html"
  ];

  function load(i) {
    if (i >= urls.length) {
      document.getElementById("app").textContent = "Failed to load.";
      return;
    }

    fetch(urls[i]).then(function(res) {
      if (!res.ok) throw new Error();
      return res.text();
    }).then(function(html) {
      document.getElementById("app").innerHTML = html;
    }).catch(function() {
      load(i + 1);
    });
  }

  load(0);

})();
